const baseConfig = $('Config Reporte').first().json;
const triggerConfig = $('SetTrigger - Flujo').first()?.json || {};
const mergedFlags = { ...(baseConfig.flags || {}) };
function mergeFlag(name) {
  const value = triggerConfig[name];
  if (value === undefined || value === null || value === '') return;
  if (typeof value === 'boolean') mergedFlags[name] = value;
  else if (typeof value === 'number') mergedFlags[name] = value !== 0;
  else {
    const text = String(value).trim().toLowerCase();
    if (['true','1','yes','y','si','s','on','enabled'].includes(text)) mergedFlags[name] = true;
    else if (['false','0','no','n','off','disabled'].includes(text)) mergedFlags[name] = false;
  }
}
for (const key of ['include_attachment','include_detail','include_summary','include_operational_notes','include_itop_button_footer','send_email','include_requirements','include_incidents','include_changes','include_problems']) mergeFlag(key);
const config = { ...baseConfig, ...triggerConfig, flags: mergedFlags };
for (const [key, value] of Object.entries(mergedFlags)) config[key] = value;

const statusInventario = String(config.available_status_values || 'stock')
  .split(',')
  .map(v => v.trim().toLowerCase())
  .filter(Boolean);

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function getField(obj, names, fallback = '') {
  for (const name of names) {
    if (obj && obj[name] !== undefined && obj[name] !== null && obj[name] !== '') return obj[name];
    if (obj?.fields && obj.fields[name] !== undefined && obj.fields[name] !== null && obj.fields[name] !== '') return obj.fields[name];
  }
  return fallback;
}

function flattenInput(items) {
  const rows = [];

  for (const item of items) {
    const j = item.json || {};

    if (j.objects && typeof j.objects === 'object') {
      for (const [key, value] of Object.entries(j.objects)) {
        rows.push({
          key,
          ...(value || {}),
          fields: value?.fields || value || {},
        });
      }
      continue;
    }

    if (Array.isArray(j)) {
      rows.push(...j);
      continue;
    }

    rows.push(j);
  }

  return rows;
}

function normalizeClass(value) {
  const raw = String(value || '-').trim();
  const lower = raw.toLowerCase();

  if (lower === 'pc' || lower.includes('desktop')) return 'PC';
  if (lower === 'laptop' || lower.includes('notebook') || lower.includes('portable')) return 'Laptop';
  if (lower === 'mobilephone' || lower.includes('phone') || lower.includes('telefono') || lower.includes('tel\u00e9fono')) return 'Tel\u00e9fonos m\u00f3viles';
  if (lower === 'tablet') return 'Tablets';
  if (lower === 'printer' || lower.includes('impresora')) return 'Impresoras';
  if (lower === 'peripheral' || lower.includes('periferico') || lower.includes('perif\u00e9rico')) return 'Perif\u00e9ricos';

  return raw || 'Otros';
}

function classSortWeight(className) {
  const order = {
    'PC': 10,
    'Laptop': 20,
    'Tablets': 30,
    'Tel\u00e9fonos m\u00f3viles': 40,
    'Impresoras': 50,
    'Perif\u00e9ricos': 60,
    'Otros': 90,
  };
  return order[className] || 80;
}

function isBlankValue(value) {
  const v = String(value ?? '').trim();
  return !v || v === '-' || v.toLowerCase() === 'n/a' || v.toLowerCase() === 'null' || v.toLowerCase() === 'undefined';
}


function translatePhysicalDeviceStatus(value) {
  const status = String(value || '').trim().toLowerCase();
  const map = {
    stock: 'En Inventario',
    implementation: 'No Productivo',
    production: 'Productivo',
    obsolete: 'Obsoleto',
  };
  return map[status] || String(value || '-');
}

function reviewReasons(asset) {
  const reasons = [];
  if (isBlankValue(asset.serial)) reasons.push('sin serie');
  if (isBlankValue(asset.brand)) reasons.push('sin marca');
  if (isBlankValue(asset.model)) reasons.push('sin modelo');
  if (isBlankValue(asset.warehouse) || asset.warehouse === 'Sin bodega/localidad') reasons.push('sin bodega/localidad');
  return reasons;
}

function badge(text, color = 'gray') {
  return `<span class="badge badge-${color}">${escapeHtml(text)}</span>`;
}

const rawRows = flattenInput($input.all());

const assets = rawRows
  .map((row) => {
    const fields = row.fields || row;
    const finalclassRaw = getField(fields, ['finalclass', 'class'], '-');
    const finalclass = normalizeClass(finalclassRaw);

    return {
      name: getField(fields, ['name', 'friendlyname'], '-'),
      finalclass,
      finalclassRaw,
      statusRaw: String(getField(fields, ['status'], '-')).trim().toLowerCase(),
      status: translatePhysicalDeviceStatus(getField(fields, ['status'], '-')),
      organization: getField(fields, ['org_id_friendlyname', 'organization_name'], '-'),
      warehouse: getField(fields, ['location_id_friendlyname', 'location_name', 'location_id'], 'Sin bodega/localidad'),
      brand: getField(fields, ['brand_id_friendlyname', 'brand'], '-'),
      model: getField(fields, ['model_id_friendlyname', 'model'], '-'),
      serial: getField(fields, ['serialnumber', 'serial_number'], ''),
      assetNumber: getField(fields, ['asset_number', 'asset_tag'], ''),
      move2production: getField(fields, ['move2production', 'production_date'], '-'),
      purchaseDate: getField(fields, ['purchase_date'], '-'),
      warrantyEnd: getField(fields, ['end_of_warranty'], '-'),
    };
  })
  .filter(asset => {
    const currentStatus = String(asset.statusRaw || '').toLowerCase();
    return statusInventario.some(s => currentStatus === s);
  });

assets.sort((a, b) =>
  classSortWeight(a.finalclass) - classSortWeight(b.finalclass) ||
  String(a.finalclass).localeCompare(String(b.finalclass), 'es') ||
  String(a.warehouse).localeCompare(String(b.warehouse), 'es') ||
  String(a.name).localeCompare(String(b.name), 'es')
);

const classGroups = new Map();
const warehouses = new Map();
const reviewAssets = [];

let withoutSerial = 0;

for (const asset of assets) {
  if (!classGroups.has(asset.finalclass)) classGroups.set(asset.finalclass, []);
  classGroups.get(asset.finalclass).push(asset);

  if (!warehouses.has(asset.warehouse)) warehouses.set(asset.warehouse, []);
  warehouses.get(asset.warehouse).push(asset);

  if (isBlankValue(asset.serial)) withoutSerial++;

  const reasons = reviewReasons(asset);
  if (reasons.length > 0) {
    reviewAssets.push({ ...asset, reviewReasonText: reasons.join(', ') });
  }
}

const orderedClassEntries = Array.from(classGroups.entries()).sort(([a], [b]) =>
  classSortWeight(a) - classSortWeight(b) || a.localeCompare(b, 'es')
);

const classSummaryRows = orderedClassEntries.map(([className, list]) => {
  const byWarehouse = {};
  let incomplete = 0;

  for (const asset of list) {
    byWarehouse[asset.warehouse] = (byWarehouse[asset.warehouse] || 0) + 1;
    if (reviewReasons(asset).length > 0) incomplete++;
  }

  const warehousesText = Object.entries(byWarehouse)
    .sort(([a], [b]) => a.localeCompare(b, 'es'))
    .map(([warehouse, count]) => `${escapeHtml(warehouse)}: ${count}`)
    .join('<br>');

  const observation = incomplete > 0
    ? `<span class="badge badge-yellow">Por revisar: ${incomplete}</span>`
    : `<span class="badge badge-green">Sin observaciones</span>`;

  return `
    <tr>
      <td style="font-size:12px; line-height:16px; color:#1f2937; padding:8px 7px; border-bottom:1px solid #edf2f7; vertical-align:top;"><strong>${escapeHtml(className)}</strong></td>
      <td align="right" style="font-size:12px; line-height:16px; color:#1f2937; padding:8px 7px; border-bottom:1px solid #edf2f7; vertical-align:top;"><strong>${list.length}</strong></td>
      <td style="font-size:12px; line-height:16px; color:#1f2937; padding:8px 7px; border-bottom:1px solid #edf2f7; vertical-align:top;">${warehousesText || '-'}</td>
      <td style="font-size:12px; line-height:16px; color:#1f2937; padding:8px 7px; border-bottom:1px solid #edf2f7; vertical-align:top;">${observation}</td>
    </tr>
  `;
}).join('');

const warehouseSummaryRows = Array.from(warehouses.entries()).sort(([a], [b]) => a.localeCompare(b, 'es')).map(([warehouse, list]) => {
  const classCounts = {};
  for (const asset of list) {
    classCounts[asset.finalclass] = (classCounts[asset.finalclass] || 0) + 1;
  }

  const classesText = Object.entries(classCounts)
    .sort(([a], [b]) => classSortWeight(a) - classSortWeight(b) || a.localeCompare(b, 'es'))
    .map(([name, count]) => `${escapeHtml(name)}: ${count}`)
    .join('<br>');

  const incomplete = list.filter(a => reviewReasons(a).length > 0).length;

  const observation = incomplete > 0
    ? `<span class="badge badge-yellow">Por revisar: ${incomplete}</span>`
    : `<span class="badge badge-green">Sin observaciones</span>`;

  return `
    <tr>
      <td style="font-size:12px; line-height:16px; color:#1f2937; padding:8px 7px; border-bottom:1px solid #edf2f7; vertical-align:top;">${escapeHtml(warehouse)}</td>
      <td align="right" style="font-size:12px; line-height:16px; color:#1f2937; padding:8px 7px; border-bottom:1px solid #edf2f7; vertical-align:top;"><strong>${list.length}</strong></td>
      <td style="font-size:12px; line-height:16px; color:#1f2937; padding:8px 7px; border-bottom:1px solid #edf2f7; vertical-align:top;">${classesText}</td>
      <td style="font-size:12px; line-height:16px; color:#1f2937; padding:8px 7px; border-bottom:1px solid #edf2f7; vertical-align:top;">${observation}</td>
    </tr>
  `;
}).join('');

function assetRows(list, includeReviewColumn = false) {
  return list.map(asset => {
    const serialBadge = !isBlankValue(asset.serial)
      ? escapeHtml(asset.serial)
      : '<span class="badge badge-yellow">Sin serie</span>';

    const reviewColumn = includeReviewColumn
      ? `<td style="font-size:12px; line-height:16px; color:#1f2937; padding:8px 7px; border-bottom:1px solid #edf2f7; vertical-align:top;">${badge(asset.reviewReasonText || reviewReasons(asset).join(', '), 'yellow')}</td>`
      : '';

    return `
      <tr>
        <td style="font-size:12px; line-height:16px; color:#1f2937; padding:8px 7px; border-bottom:1px solid #edf2f7; vertical-align:top;">${escapeHtml(asset.finalclass)}</td>
        <td style="font-size:12px; line-height:16px; color:#1f2937; padding:8px 7px; border-bottom:1px solid #edf2f7; vertical-align:top;"><strong>${escapeHtml(asset.name)}</strong></td>
        <td style="font-size:12px; line-height:16px; color:#1f2937; padding:8px 7px; border-bottom:1px solid #edf2f7; vertical-align:top;">${escapeHtml(asset.warehouse)}</td>
        <td style="font-size:12px; line-height:16px; color:#1f2937; padding:8px 7px; border-bottom:1px solid #edf2f7; vertical-align:top;">${escapeHtml(asset.brand)}</td>
        <td style="font-size:12px; line-height:16px; color:#1f2937; padding:8px 7px; border-bottom:1px solid #edf2f7; vertical-align:top;">${escapeHtml(asset.model)}</td>
        <td style="font-size:12px; line-height:16px; color:#1f2937; padding:8px 7px; border-bottom:1px solid #edf2f7; vertical-align:top;">${serialBadge}</td>
        <td style="font-size:12px; line-height:16px; color:#1f2937; padding:8px 7px; border-bottom:1px solid #edf2f7; vertical-align:top;">${escapeHtml(asset.warrantyEnd)}</td>
        ${reviewColumn}
      </tr>
    `;
  }).join('');
}

function assetsTable(list, includeReviewColumn = false) {
  const reviewHead = includeReviewColumn
    ? '<th style="background-color:#f8fafc; color:#334155; font-size:11px; line-height:15px; font-weight:bold; text-align:left; padding:8px 7px; border-bottom:1px solid #dbe3ec;">Criterio</th>'
    : '';

  const colSpan = includeReviewColumn ? 8 : 7;

  return `
    <div class="table-scroll" style="width:100%; overflow-x:auto;">
      <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" class="data-table" style="width:100%;">
        <thead>
          <tr>
            <th style="background-color:#f8fafc; color:#334155; font-size:11px; line-height:15px; font-weight:bold; text-align:left; padding:8px 7px; border-bottom:1px solid #dbe3ec;">Clase/Tipo</th>
            <th style="background-color:#f8fafc; color:#334155; font-size:11px; line-height:15px; font-weight:bold; text-align:left; padding:8px 7px; border-bottom:1px solid #dbe3ec;">Nombre</th>
            <th style="background-color:#f8fafc; color:#334155; font-size:11px; line-height:15px; font-weight:bold; text-align:left; padding:8px 7px; border-bottom:1px solid #dbe3ec;">Bodega</th>
            <th style="background-color:#f8fafc; color:#334155; font-size:11px; line-height:15px; font-weight:bold; text-align:left; padding:8px 7px; border-bottom:1px solid #dbe3ec;">Marca</th>
            <th style="background-color:#f8fafc; color:#334155; font-size:11px; line-height:15px; font-weight:bold; text-align:left; padding:8px 7px; border-bottom:1px solid #dbe3ec;">Modelo</th>
            <th style="background-color:#f8fafc; color:#334155; font-size:11px; line-height:15px; font-weight:bold; text-align:left; padding:8px 7px; border-bottom:1px solid #dbe3ec;">Serie</th>
            <th style="background-color:#f8fafc; color:#334155; font-size:11px; line-height:15px; font-weight:bold; text-align:left; padding:8px 7px; border-bottom:1px solid #dbe3ec;">Garant\u00eda</th>
            ${reviewHead}
          </tr>
        </thead>
        <tbody>
          ${list.length ? assetRows(list, includeReviewColumn) : `<tr><td colspan="${colSpan}" style="padding:12px; font-size:12px; color:#64748b;">Sin activos para listar.</td></tr>`}
        </tbody>
      </table>
    </div>
  `;
}

const classAssetBlocks = orderedClassEntries.map(([className, list]) => `
  <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom:18px; border:1px solid #dbe3ec;">
    <tr>
      <td style="background-color:#f1f5f9; padding:10px 12px;">
        <div style="font-size:14px; line-height:20px; font-weight:bold; color:#0f172a;">
          ${escapeHtml(className)} <span style="color:#64748b; font-weight:normal;">(${list.length} activos)</span>
        </div>
        <div style="font-size:12px; line-height:18px; color:#64748b; margin-top:2px;">
          Bloque agrupado por clase CMDB normalizada desde iTop. PC y Laptop se mantienen como secciones independientes.
        </div>
      </td>
    </tr>
    <tr>
      <td>${assetsTable(list, false)}</td>
    </tr>
  </table>
`).join('');

const reviewCriteria = [
  {
    key: 'sin_serie',
    title: 'Sin n\u00famero de serie',
    description: 'Activos en inventario sin serial registrado en iTop.',
    match: (asset) => isBlankValue(asset.serial),
  },
  {
    key: 'sin_marca',
    title: 'Sin marca',
    description: 'Activos en inventario sin fabricante o marca asociada.',
    match: (asset) => isBlankValue(asset.brand),
  },
  {
    key: 'sin_modelo',
    title: 'Sin modelo',
    description: 'Activos en inventario sin modelo t\u00e9cnico registrado.',
    match: (asset) => isBlankValue(asset.model),
  },
  {
    key: 'sin_bodega',
    title: 'Sin bodega/localidad',
    description: 'Activos en inventario sin ubicaci\u00f3n f\u00edsica clara para control de stock.',
    match: (asset) => isBlankValue(asset.warehouse) || asset.warehouse === 'Sin bodega/localidad',
  },
];

const reviewAssetBlocks = reviewAssets.length
  ? reviewCriteria.map((criterion) => {
      const list = reviewAssets
        .filter(asset => criterion.match(asset))
        .sort((a, b) =>
          String(a.finalclass).localeCompare(String(b.finalclass), 'es') ||
          String(a.warehouse).localeCompare(String(b.warehouse), 'es') ||
          String(a.name).localeCompare(String(b.name), 'es')
        );

      if (!list.length) return '';

      return `
        <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom:18px; border:1px solid #dbe3ec;">
          <tr>
            <td style="background-color:#fff7ed; padding:10px 12px; border-bottom:1px solid #fed7aa;">
              <div style="font-size:14px; line-height:20px; font-weight:bold; color:#9a3412;">
                ${escapeHtml(criterion.title)} <span style="color:#64748b; font-weight:normal;">(${list.length} activos)</span>
              </div>
              <div style="font-size:12px; line-height:18px; color:#854d0e; margin-top:2px;">
                ${escapeHtml(criterion.description)} Un mismo activo puede aparecer en m\u00e1s de un criterio si presenta m\u00faltiples datos incompletos.
              </div>
            </td>
          </tr>
          <tr>
            <td>${assetsTable(list, true)}</td>
          </tr>
        </table>
      `;
    }).join('')
  : '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="border:1px solid #dbe3ec;"><tr><td style="padding:14px; font-size:13px; color:#166534;">No se detectaron activos con datos cr\u00edticos incompletos seg\u00fan el criterio del reporte.</td></tr></table>';


function csvEscape(value) {
  const text = String(value ?? '').replace(/\r?\n/g, ' ').trim();
  if (/[";\r\n]/.test(text)) {
    return `"${text.replace(/"/g, '""')}"`;
  }
  return text;
}

function slug(value) {
  return String(value || 'cmdb')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '') || 'cmdb';
}

const csvHeaders = [
  'Clase/Tipo',
  'Nombre',
  'Estado',
  'Bodega/Localidad',
  'Marca',
  'Modelo',
  'Serie',
  'Puesto en Produccion',
  'Fecha de Compra',
  'Vencimiento de Garantia',
];

const csvRows = assets.map(asset => [
  asset.finalclass,
  asset.name,
  asset.status,
  asset.warehouse,
  asset.brand,
  asset.model,
  asset.serial,
  asset.move2production,
  asset.purchaseDate,
  asset.warrantyEnd,
]);

const csvContent = '\uFEFF' + [
  csvHeaders.map(csvEscape).join(';'),
  ...csvRows.map(row => row.map(csvEscape).join(';')),
].join('\r\n');

const generatedAt = new Date().toLocaleString('es-CL', {
  timeZone: config.timezone || 'America/Santiago',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
});


const itopOrganization = String(config.itop_organization || '').trim();
const generatedAtFile = new Date()
  .toISOString()
  .replace(/[:.]/g, '-')
  .replace('T', '_')
  .slice(0, 19);

const company = String(config.Company || config.company || 'TecnoComp').trim();
const baseSubject = String(config.email_subject || 'Reporte CMDB - activos en inventario agrupados por clase').trim();
const subjectWithOrganization = itopOrganization
  ? `${baseSubject} - ${itopOrganization}`
  : baseSubject;

return [
  {
    json: {
      flags: config.flags || {},
      include_attachment: config.flags?.include_attachment ?? config.include_attachment,
      include_detail: config.flags?.include_detail ?? config.include_detail,
      include_summary: config.flags?.include_summary ?? config.include_summary,
      include_operational_notes: config.flags?.include_operational_notes ?? config.include_operational_notes,
      include_itop_button_footer: config.flags?.include_itop_button_footer ?? config.include_itop_button_footer,
      email_from: config.email_from || 'blk.zeus@gmail.com',
      email_to: config.email_to,
      email_cc: config.email_cc || '',
      email_bcc: config.email_bcc || '',
      email_subject: subjectWithOrganization,
      itop_organization: itopOrganization,
      Company: company,
      company,
      report_source_label: config.report_source_label || 'Producci\u00f3n / iTop CMDB',
      generated_at: generatedAt,
      total_available: String(assets.length),
      warehouse_count: String(warehouses.size),
      class_count: String(classGroups.size),
      without_serial_count: String(withoutSerial),
      review_count: String(reviewAssets.length),
      csv_file_name: `cmdb_stock_${slug(itopOrganization || company)}_${generatedAtFile}.csv`,
      class_summary_rows: classSummaryRows || '<tr><td colspan="4" style="padding:12px; font-size:12px; color:#64748b;">Sin activos en inventario recuperados desde iTop.</td></tr>',
      warehouse_summary_rows: warehouseSummaryRows || '<tr><td colspan="4" style="padding:12px; font-size:12px; color:#64748b;">Sin activos en inventario recuperados desde iTop.</td></tr>',
      class_asset_blocks: classAssetBlocks || '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="border:1px solid #dbe3ec;"><tr><td style="padding:14px; font-size:13px; color:#64748b;">Sin activos en inventario para listar.</td></tr></table>',
      review_asset_blocks: reviewAssetBlocks,
      itop_url: config.itop_url || '#',
    },
    binary: {
      csv: {
        data: Buffer.from(csvContent, 'utf8').toString('base64'),
        mimeType: 'text/csv; charset=utf-8',
        fileName: `cmdb_stock_${slug(itopOrganization || company)}_${generatedAtFile}.csv`,
        fileExtension: 'csv',
      },
    },
  },
];

const inputItem = $input.first();
const data = inputItem.json || {};
const binary = inputItem.binary || {};

function getNodeJson(name) {
  try { return $(name).first()?.json || {}; } catch (error) { return {}; }
}

function flagEnabled(name, fallback = true) {
  const trigger = getNodeJson('SetTrigger - Flujo');
  const mixed = getNodeJson('SetMixed - Configuracion efectiva');
  const value = trigger[name] ?? trigger.flags?.[name] ?? data[name] ?? data.flags?.[name] ?? mixed[name] ?? mixed.flags?.[name];
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  const text = String(value).trim().toLowerCase();
  if (['true', '1', 'yes', 'y', 'si', 's', 'on', 'enabled'].includes(text)) return true;
  if (['false', '0', 'no', 'n', 'off', 'disabled'].includes(text)) return false;
  return fallback;
}

function removeOuterRowByMarker(html, marker) {
  let index = html.indexOf(marker);
  if (index === -1) return html;
  const starts = ['\n      <tr><td', '\n                        <tr><td', '\n                        <tr><td align', '\n      <tr><td align'];
  let start = -1;
  for (const token of starts) {
    const candidate = html.lastIndexOf(token, index);
    if (candidate > start) start = candidate;
  }
  if (start === -1) start = html.lastIndexOf('<tr><td', index);
  if (start === -1) return html;
  let end = html.indexOf('\n\n      <tr><td', index);
  const endAlt = html.indexOf('\n\n                        <tr><td', index);
  if (end === -1 || (endAlt !== -1 && endAlt < end)) end = endAlt;
  const footerAlt = html.indexOf('\n      <tr><td style="background-color', index);
  if (end === -1 || (footerAlt !== -1 && footerAlt < end)) end = footerAlt;
  const footerAlt2 = html.indexOf('\n                        <tr><td style="background-color', index);
