function removeOuterRowByMarker(html, marker) {
  const index = html.indexOf(marker);
  if (index === -1) return html;
  const starts = ['\n      <tr><td', '\n                        <tr><td', '<tr><td', '<tr>'];
  let start = -1;
  for (const needle of starts) {
    const pos = html.lastIndexOf(needle, index);
    if (pos !== -1 && pos > start) start = pos;
  }
  if (start === -1) start = Math.max(0, index - 200);
  const ends = ['\n      <tr><td', '\n                        <tr><td', '\n      <tr><td style="background-color', '\n                        <tr><td style="background-color'];
  let end = -1;
  for (const needle of ends) {
    const pos = html.indexOf(needle, index + marker.length);
    if (pos !== -1 && (end === -1 || pos < end)) end = pos;
  }
  if (end === -1) {
    const close = html.indexOf('</td></tr>', index);
    end = close === -1 ? index + marker.length : close + '</td></tr>'.length;
  }
  return html.slice(0, start) + html.slice(end);
}

function removeAllRowsByMarker(html, marker) {
  let previous;
  do {
    previous = html;
    html = removeOuterRowByMarker(html, marker);
  } while (html !== previous);
  return html;
}

